+    // Only propagate relevant flags (nnan, nsz) to the select.
+    FastMathFlags SelectNewFMF = FastMathFlags::intersectRewrite(SelectFMF, FAddFMF) |
+                                 (FastMathFlags::unionValue(SelectFMF, FAddFMF) &
+                                  ~FastMathFlags(FastMathFlags::NoInfs));
+    cast<Instruction>(NewSelect)->setFastMathFlags(SelectNewFMF);

     return NewFAdd;
   };
